mapper.select:
SELECT l.id, l.spare_part_id AS sparePartId, s.part_name AS partName, s.part_code AS partCode, l.action_type AS actionType, l.quantity, l.project_id AS projectId, p.project_name AS projectName, l.operator_id AS operatorId, l.remark, l.create_time AS createTime FROM spare_part_log l LEFT JOIN spare_part s ON s.id = l.spare_part_id AND s.deleted = 0 LEFT JOIN project p ON p.id = l.project_id AND p.deleted = 0
l.deleted = 0
AND l.spare_part_id = #{sparePartId}
AND l.project_id = #{projectId}
AND l.action_type = #{actionType}
ORDER BY l.create_time DESC, l.id DESC
